@Configuration
@EnableWebSecurity
class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http, SamlAuthenticationFilter samlAuthenticationFilter) throws Exception {
        http
            .csrf(csrf -> csrf.disable())
            .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/saml/acs", "/saml/login", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .addFilterBefore(samlAuthenticationFilter, AbstractPreAuthenticatedProcessingFilter.class)
            .httpBasic(Customizer.withDefaults())
            .formLogin(form -> form.disable());

        return http.build();
    }
}

@Component
class SamlAuthenticationFilter extends OncePerRequestFilter {

    private final SamlResponseProcessor samlResponseProcessor;

    SamlAuthenticationFilter(SamlResponseProcessor samlResponseProcessor) {
        this.samlResponseProcessor = samlResponseProcessor;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        return !"/saml/acs".equals(request.getRequestURI()) || !"POST".equalsIgnoreCase(request.getMethod());
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        String samlResponse = request.getParameter("SAMLResponse");
        if (samlResponse == null || samlResponse.isBlank()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing SAMLResponse");
            return;
        }

        try {
            SamlAssertionData assertionData = samlResponseProcessor.processSamlResponse(samlResponse);

            List<SimpleGrantedAuthority> authorities = new ArrayList<>();
            if (assertionData.roles() != null) {
                for (String role : assertionData.roles()) {
                    authorities.add(new SimpleGrantedAuthority(role.startsWith("ROLE_") ? role : "ROLE_" + role));
                }
            }
            if (authorities.isEmpty()) {
                authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
            }

            Authentication authentication = new UsernamePasswordAuthenticationToken(
                    assertionData.nameId(),
                    "N/A",
                    authorities
            );

            SecurityContextHolder.getContext().setAuthentication(authentication);

            HttpSession session = request.getSession(true);
            session.setAttribute("authenticated", Boolean.TRUE);
            session.setAttribute("nameId", assertionData.nameId());
            session.setAttribute("issuer", assertionData.issuer());
            session.setAttribute("sessionIndex", assertionData.sessionIndex());
            session.setAttribute("attributes", assertionData.attributes());
            session.setAttribute("roles", assertionData.roles());
            session.setAttribute("authentication", authentication);

            response.sendRedirect(request.getContextPath() + "/");
        } catch (Exception e) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid SAMLResponse: " + e.getMessage());
        }
    }
}

@Service
class SamlResponseProcessor {

    public SamlAssertionData processSamlResponse(String base64Response) throws Exception {
        String xml = decodeBase64(base64Response);
        Document document = parseXml(xml);

        Node assertion = findFirstElementByLocalName(document, "Assertion");
        if (assertion == null) {
            throw new IllegalArgumentException("No Assertion found");
        }

        String issuer = getTextContentOfFirstChildByLocalName(assertion, "Issuer");
        String nameId = getNameId(assertion);
        String sessionIndex = getAttributeValue(assertion, "SessionIndex");

        Map<String, String> attributes = extractAttributes(assertion);
        List<String> roles = extractRoles(attributes);

        return new SamlAssertionData(nameId, issuer, sessionIndex, attributes, roles);
    }

    private String decodeBase64(String base64Response) {
        Decoder decoder = Base64.getMimeDecoder();
        byte[] decoded = decoder.decode(base64Response);
        return new String(decoded, StandardCharsets.UTF_8);
    }

    private Document parseXml(String xml) throws ParserConfigurationException, IOException, SAXException {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setExpandEntityReferences(false);

        DocumentBuilder builder = dbf.newDocumentBuilder();
        try (StringReader reader = new StringReader(xml)) {
            return builder.parse(new InputSource(reader));
        }
    }

    private Node findFirstElementByLocalName(Node node, String localName) {
        if (node == null) return null;
        if (node.getNodeType() == Node.ELEMENT_NODE && localName.equals(node.getLocalName())) {
            return node;
        }
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node found = findFirstElementByLocalName(children.item(i), localName);
            if (found != null) return found;
        }
        return null;
    }

    private String getTextContentOfFirstChildByLocalName(Node node, String localName) {
        if (node == null) return null;
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && localName.equals(child.getLocalName())) {
                return child.getTextContent();
            }
        }
        return null;
    }

    private String getNameId(Node assertion) {
        Node subject = findFirstChildByLocalName(assertion, "Subject");
        if (subject == null) return null;
        Node nameId = findFirstChildByLocalName(subject, "NameID");
        return nameId != null ? nameId.getTextContent() : null;
    }

    private String getAttributeValue(Node assertion, String attributeName) {
        Node authnStatement = findFirstChildByLocalName(assertion, "AuthnStatement");
        if (authnStatement == null) return null;
        NamedNodeMap attrs = authnStatement.getAttributes();
        Node attr = attrs != null ? attrs.getNamedItem(attributeName) : null;
        return attr != null ? attr.getNodeValue() : null;
    }

    private Node findFirstChildByLocalName(Node node, String localName) {
        if (node == null) return null;
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && localName.equals(child.getLocalName())) {
                return child;
            }
        }
        return null;
    }

    private Map<String, String> extractAttributes(Node assertion) {
        Map<String, String> attributes = new LinkedHashMap<>();
        Node attributeStatement = findFirstChildByLocalName(assertion, "AttributeStatement");
        if (attributeStatement == null) return attributes;

        NodeList children = attributeStatement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() != Node.ELEMENT_NODE || !"Attribute".equals(child.getLocalName())) continue;

            NamedNodeMap attrMap = child.getAttributes();
            Node nameNode = attrMap != null ? attrMap.getNamedItem("Name") : null;
            if (nameNode == null) continue;

            String attrName = nameNode.getNodeValue();
            StringBuilder value = new StringBuilder();
            NodeList values = child.getChildNodes();
            for (int j = 0; j < values.getLength(); j++) {
                Node valNode = values.item(j);
                if (valNode.getNodeType() == Node.ELEMENT_NODE && "AttributeValue".equals(valNode.getLocalName())) {
                    if (value.length() > 0) value.append(",");
                    value.append(valNode.getTextContent());
                }
            }
            attributes.put(attrName, value.toString());
        }
        return attributes;
    }

    private List<String> extractRoles(Map<String, String> attributes) {
        List<String> roles = new ArrayList<>();
        for (Map.Entry<String, String> entry : attributes.entrySet()) {
            String key = entry.getKey().toLowerCase(Locale.ROOT);
            if (key.contains("role") || key.contains("groups") || key.contains("group")) {
                String[] parts = entry.getValue().split("[,;\\s]+");
                for (String part : parts) {
                    if (!part.isBlank()) roles.add(part.trim());
                }
            }
        }
        return roles;
    }
}

