@Controller
@RequestMapping("/")
class HomeController {

    @GetMapping
    @ResponseBody
    public String home(HttpSession session, Principal principal) {
        Object auth = session.getAttribute("authenticated");
        if (!Boolean.TRUE.equals(auth)) {
            return "Not authenticated";
        }

        StringBuilder sb = new StringBuilder();
        sb.append("Authenticated\n");
        sb.append("Principal: ").append(principal != null ? HtmlUtils.htmlEscape(principal.getName()) : "unknown").append("\n");
        sb.append("NameID: ").append(value(session.getAttribute("nameId"))).append("\n");
        sb.append("Issuer: ").append(value(session.getAttribute("issuer"))).append("\n");
        sb.append("SessionIndex: ").append(value(session.getAttribute("sessionIndex"))).append("\n");
        sb.append("Attributes: ").append(value(session.getAttribute("attributes"))).append("\n");
        sb.append("Roles: ").append(value(session.getAttribute("roles"))).append("\n");
        return sb.toString();
    }

    private String value(Object o) {
        return o == null ? "" : HtmlUtils.htmlEscape(String.valueOf(o));
    }
}

